    entries.forEach(entry => {
        if (entry.isIntersecting) {
            // 一度表示された要素は再度アニメーションしないように制御
            if (!entry.target.classList.contains('in-view')) {
                entry.target.classList.add('in-view');
            }
        }
    });
}, { 
